/* Test driver */
import java.util.*;
public class Main {
    public static void main(String[] args) {
        SplitwiseService s = new SplitwiseService();
        User alice = s.addUser("u1", "Alice", "a@b.com");
        User bob = s.addUser("u2", "Bob", "b@b.com");
        s.createGroup("g1", "G", Arrays.asList(alice, bob));
        s.addGroupExpense("g1", "e1", "Lunch", 100.0, alice, new SplitStrategy.EqualSplit(), new HashMap<>());
        List<Balance> bs = s.getBalances();
        boolean found = false;
        for (Balance b : bs) {
            if (b.getFrom() == bob && b.getTo() == alice && Math.abs(b.getAmount() - 50.0) < 0.01) found = true;
        }
        if (found) System.out.println("OK_EQUAL");
    }
}

