import java.util.*;
public class Main {
    public static void main(String[] args) {
        SplitwiseService s = new SplitwiseService();
        User a = s.addUser("u1", "A", "a@x");
        User b = s.addUser("u2", "B", "b@x");
        User c = s.addUser("u3", "C", "c@x");
        s.createGroup("g1", "G", Arrays.asList(a, b, c));
        Map<User, Double> p = new HashMap<>();
        p.put(a, 50.0); p.put(b, 30.0); p.put(c, 20.0);
        s.addGroupExpense("g1", "e1", "X", 100.0, a, new SplitStrategy.PercentageSplit(), p);
        List<Balance> bs = s.getBalances();
        double bToA = 0, cToA = 0;
        for (Balance bal : bs) {
            if (bal.getFrom() == b && bal.getTo() == a) bToA = bal.getAmount();
            if (bal.getFrom() == c && bal.getTo() == a) cToA = bal.getAmount();
        }
        if (Math.abs(bToA - 30.0) < 0.01 && Math.abs(cToA - 20.0) < 0.01) System.out.println("OK_PCT");
    }
}

